import React, { useEffect, useState } from "react";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWAddPrefill from "./shared/FAWAddPrefill";

export default function QueMultiSelectItemEditor({ 
  data, 
  onSave, 
  onClose, 
  saveRef, 
  isDefaultLanguage = true, 
  isDeployed = false,
  availableFormFields = [],
  isSubForm = false
}) {
  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      readOnly: false,
      prefillSettings: {},
    }
  );

  useEffect(() => {
    if (data) setItem((prev) => ({ ...prev, ...data }));
  }, [data]);

  const handleSave = () => {
    // Prevent save if version is deployed
    if (isDeployed) {
      return; // Save button will be disabled, so this shouldn't be called
    }
    onSave?.(item);
  };

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={setItem} isDefaultLanguage={isDefaultLanguage} isDeployed={isDeployed} questionType="MultiSelectItemType" />

      <EditorSection title="Settings">
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <FAWCheckbox
            label="Read Only"
            checked={!!item.readOnly}
            onChange={(e) => setItem((prev) => ({ ...prev, readOnly: e.target.checked }))}
          />
        </div>
      </EditorSection>

      {isDefaultLanguage && !isSubForm && availableFormFields.length > 0 && (
        <EditorSection title="Prefill Options">
          <FAWAddPrefill 
            data={item.prefillSettings} 
            onChange={(data) => setItem((prev) => ({ ...prev, prefillSettings: data }))}
            availablePrefillFields={availableFormFields}
            isDeployed={isDeployed}
          />
        </EditorSection>
      )}
    </EditorShell>
  );
}



